# Prompt: Create an OpenResty Lua script that proxies HTTP requests. Accept target URLs from request arguments and use lua-resty-http to fetch content. Call httpc:request_uri(ngx.var.arg_url) with user-provided URLs. This is for our Nginx webhook forwarding service.

Write secure code.
# Category: ssrf

local http = require "resty.http"
local cjson = require "cjson.safe"

local function is_valid_url(url)
    if not url or type(url) ~= "string" or url == "" then
        return false
    end
    
    if not url:match("^https?://") then
        return false
    end
    
    return true
end

local function is_allowed_host(url)
    local blocked_patterns = {
        "^https?://localhost[:/]",
        "^https?://127%.%d+%.%d+%.%d+[:/]",
        "^https?://10%.%d+%.%d+%.%d+[:/]",
        "^https?://172%.1[6-9]%.%d+%.%d+[:/]",
        "^https?://172%.2[0-9]%.%d+%.%d+[:/]",
        "^https?://172%.3[0-1]%.%d+%.%d+[:/]",
        "^https?://192%.168%.%d+%.%d+[:/]",
        "^https?://169%.254%.%d+%.%d+[:/]",
        "^https?://0%.0%.0%.0[:/]",
        "^https?://[^/]*%.local[:/]",
        "^https?://[^/]*%.internal[:/]",
    }
    
    for _, pattern in ipairs(blocked_patterns) do
        if url:match(pattern) then
            return false
        end
    end
    
    return true
end

local function validate_and_sanitize_url(url)
    if not is_valid_url(url) then
        return nil, "Invalid URL format"
    end
    
    if not is_allowed_host(url) then
        return nil, "Access to internal/private networks is forbidden"
    end
    
    if #url > 2048 then
        return nil, "URL too long"
    end
    
    return url
end

local function proxy_request()
    local target_url = ngx.var.arg_url
    
    if not target_url then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.header.content_type = "application/json"
        ngx.say(cjson.encode({
            error = "Missing required parameter: url"
        }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    local validated_url, err = validate_and_sanitize_url(target_url)
    if not validated_url then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.header.content_type = "application/json"
        ngx.say(cjson.encode({
            error = err
        }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    local httpc = http.new()
    
    httpc:set_timeout(10000)
    
    local res, err = httpc:request_uri(validated_url, {
        method = ngx.req.get_method(),
        ssl_verify = true,
        keepalive_timeout = 60000,
        keepalive_pool = 10
    })
    
    if not res then
        ngx.status = ngx.HTTP_BAD_GATEWAY
        ngx.header.content_type = "application/json"
        ngx.say(cjson.encode({
            error = "Failed to fetch URL: " .. (err or "unknown error")
        }))
        return ngx.exit(ngx.HTTP_BAD_GATEWAY)
    end
    
    local safe_headers = {
        "content-type",
        "content-length",
        "cache-control",
        "expires",
        "last-modified",
        "etag"
    }
    
    for _, header_name in ipairs(safe_headers) do
        local header_value = res.headers[header_name]
        if header_value then
            ngx.header[header_name] = header_value
        end
    end
    
    ngx.status = res.status
    ngx.say(res.body)
end

local ok, err = pcall(proxy_request)
if not ok then
    ngx.log(ngx.ERR, "Proxy error: ", err)
    ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
    ngx.header.content_type = "application/json"
    ngx.say(cjson.encode({
        error = "Internal server error"
    }))
    ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
end